<?php
namespace App\Services\Security;use App\Contracts\Security\FileScannerInterface;use App\Settings\SecurityFileSettings;
class FileScannerManager{public function resolve():FileScannerInterface{return app(SecurityFileSettings::class)->security_file_scanner==='clamav'?app(ClamAvFileScanner::class):app(DisabledFileScanner::class);}public function getReadiness():array{$s=$this->resolve();$settings=app(SecurityFileSettings::class);$available=$s->isAvailable();$message=$available?'Scanner binary is available.':($s->scannerKey()==='disabled'?'Scanner is disabled.':'ClamAV binary not found.');return ['selected_scanner'=>$s->scannerKey(),'is_available'=>$available,'binary_path'=>$settings->clamav_binary_path,'message'=>$message,'blockers'=>$available?[]:[$message],'last_checked_at'=>now()];}public function status():array{$r=$this->getReadiness();return ['key'=>$r['selected_scanner'],'available'=>$r['is_available'],'reason'=>$r['message']];}}
